			IRI lazyIri = (IRI) lazyValue(valueStore, valueStore.createIRI("urn:example:serialized"));
			assertEquals("urn:example:serialized", lazyIri.stringValue());
			clearStringState(lazyIri, "iriString", "namespace", "localName");
			IRI roundTrippedIri = roundTrip((Serializable) lazyIri);
